SELECT 
FROM business_trip bt
LEFT JOIN engineer e ON e.id = bt.engineer_id AND e.deleted = 0
LEFT JOIN project p ON p.id = bt.project_id AND p.deleted = 0
LEFT JOIN sys_user approver ON approver.id = bt.approver_id AND approver.deleted = 0

    bt.deleted = 0

        AND bt.engineer_id = #{query.engineerId}


        AND bt.project_id = #{query.projectId}


        AND bt.status = #{query.status}


        AND bt.end_date >= #{query.startDate}


        AND bt.start_date <= #{query.endDate}


ORDER BY bt.start_date DESC, bt.id DESC
